                        print(f"    template_start: '{fc.get('template_start')}'")
                        print(f"    template_end: '{fc.get('template_end')}'")
                        print(f"    forecast_start: '{fc.get('forecast_start')}'")
                        print(f"    forecast_end: '{fc.get('forecast_end')}'")
                    
